1147       if ((WrapFlags & OverflowingBinaryOperator::NoSignedWrap) &&
1148           !Op->hasNoSignedWrap())
1149         return false;
1150       return L.match(Op->getOperand(0)) && R.match(Op->getOperand(1));
1151     }
1152     return false;
1153   }
